                <ProductCard key={i} p={p} onClick={handleClick} addItem={addItem} isWished={isWished} toggleWish={toggle} />
              ))}
            </div>
          </div>
        ))}
      </div></section>
      <Footer />
      <CartSidebar open={cartOpen} onClose={() => setCartOpen(false)} />
      <ProductModal product={selectedProduct} onClose={() => setSelectedProduct(null)} addItem={addItem} isWished={isWished} toggleWish={toggle} />
      <CookieConsent />
    </>
  )
}

export default function TiendaPage() {
  return (
    <CartProvider>
      <ToastProvider>
        <TiendaContent />
      </ToastProvider>
    </CartProvider>
  )
}
